export interface LinkRevealData {
  favicon: string | null;
  primaryColor: string | null;
}

import type { LinkRevealData } from "./types";

const THEME_COLOR_REGEX =
  /<meta[^>]*name=["']theme-color["'][^>]*content=["']([^"']+)["']/iu;
const THEME_COLOR_CONTENT_REGEX =
  /<meta[^>]*content=["']([^"']+)["'][^>]*name=["']theme-color["']/iu;

const EMPTY_DATA: LinkRevealData = {
  favicon: null,
  primaryColor: null,
};

const extractContent = (match: RegExpMatchArray | null): string | null =>
  match?.at(1) ?? null;

const getFaviconUrl = (url: string): string => {
  try {
    const { hostname } = new URL(url);
    return `https://www.google.com/s2/favicons?domain=${hostname}&sz=32`;
  } catch {
    return "";
  }
};

export const fetchLinkRevealData = async (
  url: string
): Promise<LinkRevealData> => {
  try {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 5000);

    const response = await fetch(url, {
      headers: { "User-Agent": "Mozilla/5.0 (compatible; LinkReveal/1.0)" },
      signal: controller.signal,
    });

    clearTimeout(timeoutId);

    if (!response.ok) {
      return { ...EMPTY_DATA, favicon: getFaviconUrl(url) };
    }

    const html = await response.text();
    const themeColorMatch =
      html.match(THEME_COLOR_REGEX) || html.match(THEME_COLOR_CONTENT_REGEX);

    return {
      favicon: getFaviconUrl(url),
      primaryColor: extractContent(themeColorMatch),
    };
  } catch {
    return EMPTY_DATA;
  }
};

"use client";

import { motion, useReducedMotion } from "motion/react";
import { useState, type ReactNode } from "react";

import { cn } from "@/lib/utils";

import type { LinkRevealData } from "./types";

export type LinkRevealProps = Omit<
  React.ComponentProps<"a">,
  | "children"
  | "onDrag"
  | "onDragEnd"
  | "onDragStart"
  | "onAnimationStart"
  | "onAnimationEnd"
> &
  Partial<LinkRevealData> & {
    children: ReactNode;
    icon?: ReactNode;
  };

export const LinkReveal = ({
  favicon,
  primaryColor,
  icon,
  className,
  children,
  ...props
}: LinkRevealProps) => {
  const reducedMotion = useReducedMotion();
  const [hovered, setHovered] = useState(false);
  const animate = reducedMotion ? false : hovered;

  return (
    <motion.a
      className={cn(
        "group/link relative inline-flex items-center font-medium",
        "underline underline-offset-2 !no-underline",
        primaryColor &&
          "hover:text-[var(--link-reveal-color)]",
        className
      )}
      style={{
        "--link-reveal-color": primaryColor ?? undefined,
      } as React.CSSProperties}
      onHoverStart={() => setHovered(true)}
      onHoverEnd={() => setHovered(false)}
      animate={animate ? { x: -4 } : { x: 0 }}
      transition={{ type: "spring", stiffness: 400, damping: 25 }}
      {...props}
    >
      <motion.span
        aria-hidden
        className="absolute left-0 top-0 bottom-0 my-auto inline-flex size-[1.2em] items-center overflow-hidden rounded-xs"
        animate={animate ? { opacity: 1, x: 0 } : { opacity: 0, x: 4 }}
        transition={{ duration: 0.3, ease: "easeOut" }}
      >
        {icon
          ? icon
          : favicon
            ? (
                // biome-ignore lint/performance/noImgElement: registry component, favicon from external source
                <img
                  alt=""
                  className="size-full shrink-0 object-contain"
                  height={16}
                  src={favicon}
                  width={16}
                />
              )
            : null}
      </motion.span>
      <motion.span
        className="leading-none"
        animate={animate ? { paddingLeft: "1.4em" } : { paddingLeft: 0 }}
        transition={{ duration: 0.3, ease: "easeOut" }}
      >
        {children}
      </motion.span>
    </motion.a>
  );
};
